<script>
import db from './firebase'
import firebase from 'firebase'
import VueApexCharts from 'vue-apexcharts'
export default {
  data(){
    return{
      months:['Marzec','Kwiecień','Maj','Czerwiec'],
      test:1,
      login:'',
      password:'',
      logged:false,
      weight:'',
      toEdit:false,
      days:[],
      daysMarzec:[],
      daysKwiecien:[],
      daysMaj:[],
      daysCzerwiec:[],
      show:true,
      status: 'not_accepted',
      pushUps:"",
      sugar:"",
      gainer:"",
      dips:"",
      teeths:"",
      plank:"",
      month:'',
      nails:'',
      abs:false,
      
      deleteAlert:false,
      editAlert : false,
      //alert
      dismissSecs: 5,
        dismissCountDown: 0,
        showDismissibleAlert: false,
     
    }
  
  },
  beforeMount(){
    if(localStorage.getItem("logged")){
      this.logged = true;
    }
  },
  methods:{
    Login(){
       
        if(this.login == "admin" && this.password == "test"){
        this.logged = true;
        localStorage.setItem("logged",true);
        }
     
    },
    addDay(){
      this.showAlert();
        db.collection("days").add({
          pushups: this.pushUps,
          dips : this.dips,
          teeths : this.teeths,
          gainer : this.gainer,
          sugar : this.sugar,
          month : this.month,
          abs : this.abs,
          nails : this.nails,
          weight : this.weight,
          createdAt: new Date().toLocaleDateString()
      })   
      .catch(function(error) {
          console.error("Error adding collection: ", error);
      });
      },
       countDownChanged(dismissCountDown) {
        this.dismissCountDown = dismissCountDown
      },
      showAlert() {
        this.dismissCountDown = this.dismissSecs
      },
      deleteDay(day){
        this.showAlert();
        this.editAlert  = false;
        this.deleteAlert = true
        db.collection('days')
        .doc(day.id)
        .delete()
      },
      editDay(day){
        this.showAlert();
        this.deleteAlert = false;
        this.editAlert = true;
         db.collection('days')
         .doc(day.id)
          .update({
            pushups: this.pushUps,
          dips : this.dips,
          teeths : this.teeths,
          gainer : this.gainer,
          sugar : this.sugar,
          plank : this.plank,
          nails : this.nails,
          updatedAt : new Date().toLocaleDateString()
          })
      }
    
  },
  
//   mounted(){
