// .catch((error) => {
//     console.error("Error adding document: ", error);
// });
//   }
  firestore:{
    days: db.collection('days').orderBy('createdAt'),
    daysMarzec: db.collection("days").where("month", "==", "Marzec"),
    daysKwiecien: db.collection("days").where("month", "==", "Kwiecień"),
    daysMaj: db.collection("days").where("month", "==", "Maj"),
    daysCzerwiec: db.collection("days").where("month", "==", "Czerwiec"),
    
  }
}

